@staticmethod
def _validate(name: str, value: object) -> None:
    """Raise TypeError or ValueError for invalid parameter values."""
    if not isinstance(value, (int, float)):
        raise TypeError(
            f"{name} must be a number, got {type(value).__name__!r}"
        )
    # NaN check must come before the numeric comparisons because NaN
    # comparisons always return False (e.g., nan <= 0 is False).
    if isinstance(value, float) and math.isnan(value):
        raise ValueError(f"{name} must not be NaN")
    if isinstance(value, float) and math.isinf(value):
        raise ValueError(f"{name} must be finite, got {value!r}")
    if value <= 0:
        raise ValueError(f"{name} must be positive, got {value!r}")
